/**
 * Telemetry type definitions
 */
/**
 * Attributes attached to a telemetry event.
 */
interface TelemetryAttributes {
    [key: string]: string | number | boolean;
}
/**
 * Per-tenant context applied to every emitted event.
 */
interface TelemetryContext {
    baseUrl?: string;
    orgName?: string;
    tenantName?: string;
    orgId?: string;
    tenantId?: string;
    clientId?: string;
    redirectUri?: string;
}
/**
 * Identity values supplied by the consumer SDK
 * when initializing the singleton client. These describe the producer
 * of the telemetry, not the user/tenant context.
 */
interface TelemetryClientInitOptions {
    /** SDK / app version reported as `Version` and `ai.cloud.roleInstance`. */
    sdkVersion: string;
    /** Logical service name reported as `ApplicationName`. */
    serviceName: string;
    /** Cloud role name reported as `ai.cloud.role`. */
    cloudRoleName: string;
    /** Logger name used to scope log records. */
    loggerName: string;
    /** Default event display name used when none is supplied to `track`. */
    defaultEventName: string;
    /** Optional per-tenant context applied to every event. */
    context?: TelemetryContext;
}
/**
 * Options accepted by the `@track` decorator and `track(...)` function form.
 */
interface TrackOptions {
    /**
     * Either a static boolean or a callback receiving the wrapped function's
     * arguments. When `false` (or returns `false`), the call is not tracked.
     */
    condition?: boolean | ((this: unknown, ...args: unknown[]) => boolean);
    /** Extra attributes merged into the emitted event's attributes. */
    attributes?: TelemetryAttributes;
}

/**
 * Telemetry client owned by a single consumer (e.g. the SDK or the Coded
 * Action Apps package). Each consumer instantiates its own client so that
 * its identity (`cloudRoleName`, `serviceName`, `sdkVersion`, …) and tenant
 * context flow through to its own `Logger` and exporter pipeline. Two
 * consumers running in the same process emit independent events — they
 * share the Application Insights connection string but nothing else.
 *
 * Records are emitted via `Logger.emit` and batched by
 * `BatchLogRecordProcessor` before being handed to the Application Insights
 * exporter.
 */
declare class TelemetryClient {
    private isInitialized;
    private options?;
    private logProvider?;
    private logger?;
    private telemetryContext?;
    private cloudUserId?;
    initialize(options: TelemetryClientInitOptions): void;
    track(eventName: string, name?: string, extraAttributes?: TelemetryAttributes): void;
    /**
     * Default event name (e.g. `Sdk.Run`) used when a tracker fires without
     * an explicit display name. Returns `undefined` until `initialize` runs.
     */
    getDefaultEventName(): string | undefined;
    /**
     * Sets the authenticated user's id, reported as `CloudUserId` on every
     * subsequently emitted event. Empty values are ignored and the
     * previously set user id, if any, is kept.
     */
    setUserId(userId: string): void;
    private setupTelemetryProvider;
    private isValidConnectionString;
    private getEnrichedAttributes;
    private createCloudUrl;
}

/**
 * Each consumer ships as multiple subpath bundles and Rollup inlines this
 * shim into every one — `new TelemetryClient()` would hand each bundle its
 * own (uninitialized) client. `getOrCreateClient(name)` instead parks the
 * client on `globalThis` so every bundle shares one client per name.
 */

/**
 * Returns the named `TelemetryClient`, creating it on first access.
 *
 * @param name Stable identifier for the consumer (e.g. `"uipath-ts-sdk"`,
 *   `"uipath-ts-coded-action-apps"`). Subpath bundles within the same
 *   consumer share a client by passing the same name.
 */
declare function getOrCreateClient(name: string): TelemetryClient;

/**
 * `@track` decorator and `trackEvent` function factories.
 */

type TrackedFunction = (this: unknown, ...args: unknown[]) => unknown;
/**
 * The `track` decorator factory: invoking it with a name (and optional
 * options) returns a value that is both a `MethodDecorator` and a
 * function wrapper, so the same `track('Foo.Bar')` works as
 * `@track('Foo.Bar')` on a method or as `track('Foo.Bar')(myFn)` on a
 * standalone function.
 */
type Track = (nameOrOptions?: string | TrackOptions, options?: TrackOptions) => MethodDecorator & (<F extends TrackedFunction>(target: F) => F);
/**
 * Factory: returns a `track` decorator bound to a specific
 * `TelemetryClient`. Each consumer creates its own decorator from its own
 * client so events carry that consumer's identity.
 *
 * @example
 * ```ts
 * const sdkClient = new TelemetryClient();
 * sdkClient.initialize({ ... });
 * export const track = createTrack(sdkClient);
 *
 * // Consumer code
 * @track('Queue.GetAll')
 * async getAll() { ... }
 *
 * @track('Assets.Update', { condition: false })
 * async update() { ... }
 * ```
 */
declare function createTrack(client: TelemetryClient): Track;
/**
 * Factory: returns a `trackEvent` function bound to a specific
 * `TelemetryClient`. Use for ad-hoc tracking outside method boundaries.
 *
 * @example
 * ```ts
 * const trackEvent = createTrackEvent(sdkClient);
 * trackEvent('Sdk.Auth');
 * ```
 */
declare function createTrackEvent(client: TelemetryClient): (eventName: string, name?: string, attributes?: TelemetryAttributes) => void;

export { TelemetryClient, createTrack, createTrackEvent, getOrCreateClient };
export type { TelemetryAttributes, TelemetryClientInitOptions, TelemetryContext, Track, TrackOptions };
